import axios from 'axios';

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:8000',
  headers: { 'Content-Type': 'application/json' },
});

/* REQUEST — inject JWT */
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
  },
  (error) => Promise.reject(error)
);

/* RESPONSE — handle 401 globally */
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401 && !error.config?._retry) {
      console.warn('TERMINAL_SESSION_EXPIRED: Purging identity nodes.');
      localStorage.removeItem('token');
      if (window.location.pathname !== '/login') {
        window.location.href = '/login';
      }
    }
    return Promise.reject(error);
  }
);

export default api;


/* ── MarketSocket — authenticated WebSocket with heartbeat + reconnect ── */
class MarketSocket {
  constructor() {
    this.socket           = null;
    this.listeners        = new Set();
    this.url              = process.env.REACT_APP_WS_URL || 'ws://localhost:8000/ws/pulse';
    this.reconnectTimeout = null;
    this.heartbeatInterval = null;
    this._manualClose     = false; // ✅ fix: track intentional disconnects
  }

  connect() {
    const token = localStorage.getItem('token');

    if (this.socket?.readyState === WebSocket.OPEN) return;
    if (!token) {
      console.warn('SOCKET_DENIED: No identity token found.');
      return;
    }

    this._manualClose = false;
    this.socket = new WebSocket(`${this.url}?token=${token}`);

    this.socket.onopen = () => {
      console.log('✅ MARKET_PULSE_ESTABLISHED');
      this.startHeartbeat();
    };

    this.socket.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        this.listeners.forEach((cb) => cb(data));
      } catch (err) {
        console.error('PULSE_PARSE_ERROR:', err);
      }
    };

    this.socket.onclose = (event) => {
      this.stopHeartbeat();
      // ✅ fix: only reconnect on unexpected closure, not manual disconnect
      if (!this._manualClose && event.code !== 1000) {
        console.warn('⚠️ MARKET_PULSE_OFFLINE. Retrying in 5s...');
        this.reconnect();
      }
    };

    this.socket.onerror = (err) => {
      console.error('SOCKET_CRITICAL_FAILURE:', err);
      this.socket.close(); // triggers onclose → reconnect
    };
  }

  reconnect() {
    if (this.reconnectTimeout) return; // ✅ fix: guard already exists, keep it
    this.reconnectTimeout = setTimeout(() => {
      this.reconnectTimeout = null;
      this.connect();
    }, 5000);
  }

  startHeartbeat() {
    this.stopHeartbeat(); // ✅ fix: clear any existing interval before starting new one
    this.heartbeatInterval = setInterval(() => {
      if (this.socket?.readyState === WebSocket.OPEN) {
        this.socket.send(JSON.stringify({ type: 'ping' }));
      }
    }, 30000);
  }

  stopHeartbeat() {
    clearInterval(this.heartbeatInterval);
    this.heartbeatInterval = null;
  }

  subscribe(tickers) {
    if (this.socket?.readyState === WebSocket.OPEN) {
      this.socket.send(JSON.stringify({ action: 'subscribe', tickers }));
    } else {
      console.error('SUBSCRIBE_FAILED: Socket not ready.');
    }
  }

  addListener(callback) {
    this.listeners.add(callback);
    return () => this.listeners.delete(callback); // cleanup for useEffect
  }

  disconnect() {
    this._manualClose = true; // ✅ fix: flag so onclose doesn't trigger reconnect
    this.stopHeartbeat();
    if (this.reconnectTimeout) {
      clearTimeout(this.reconnectTimeout); // ✅ fix: cancel pending reconnect on logout
      this.reconnectTimeout = null;
    }
    if (this.socket) {
      this.socket.close(1000, 'User logout');
      this.socket = null;
    }
  }
}

export const marketSocket = new MarketSocket(); // ✅ fix: named export so it's not confused with api default
